from flask import Flask, request, jsonify
import os
app = Flask(__name__) 

@app.route('/', methods=['OPTIONS'])  
def allow_cross_origin():   
     return '', 204 # No content with status code 204 (No Content) to acknowledge the OPTIONS request, and also CORS headers are set here for allowing requests from any origin. You can change it according your needs if you want a specific IP or domain allowed access in production environment
     
@app.route('/', methods=['POST'])  # Route that will be called when making POST Request to the server, with data being sent as JSON format here (JSON Data)  
def handle_request():   
     requestData = request.get_json()         
     
     if 'data' not in requestData:            
         return jsonify({"error":"Missing required parameter(s)"}), 406 # Not Acceptable, missing data or wrong parameters are sent back to the client with a message saying so.  
      
     else :   
          print (requestData['data'])          
          return jsonify({"success":"Request received successfully!"}) ,201  # Returning response after successful request, and status code is set as 'Created' to indicate a new resource was created.  
     
if __name__ == "__main__":   
     app.run(host='localhost', port = 8095)